    43→export interface CanvasSliceState {
    44→  zoom: number;
    45→  panX: number;
    46→  panY: number;
    47→  zoomLevel: ZoomLevel;
    48→  viewport: ViewportBounds;
    49→  layers: LayerVisibility;
    50→  selection: CanvasSelection;
    51→  todayDate: string;
    52→  isViewportLocked: boolean;
    53→  showMinimap: boolean;
    54→  showGrid: boolean;
    55→  isPerformanceMode: boolean;
    56→  isPanning: boolean;
    57→  isZooming: boolean;
    58→  animationTarget: AnimationTarget;
    59→  [key: string]: unknown;
    60→}
    61→
    62→const initialCanvasState: CanvasSliceState = {
    63→  zoom: 10,
    64→  panX: 0,
    65→  panY: 0,
    66→  zoomLevel: 'TACTICAL',
    67→  viewport: {
    68→    startDate: new Date().toISOString().split('T')[0],
    69→    endDate: new Date(Date.now() + 84 * 24 * 60 * 60 * 1000).toISOString().split('T')[0],
    70→    trainIds: [],
    71→  },
    72→  layers: {
    73→    pmBlocks: true,
    74→    complianceWindows: true,
    75→    manhourOverlay: false,
    76→    driftOverlay: false,
    77→    baselineShadow: false,
    78→  },
    79→  selection: {
    80→    selectedPmIds: [],
    81→    selectedTrainIds: [],
    82→    isMultiSelect: false,
    83→  },
    84→  todayDate: new Date().toISOString().split('T')[0],
    85→  isViewportLocked: false,
    86→  showMinimap: true,
    87→  showGrid: true,
    88→  isPerformanceMode: false,
    89→  isPanning: false,
    90→  isZooming: false,
