  }
  if (trainIds && trainIds.length > 0) {
    params.set('trainIds', trainIds.join(','));
  }

  try {
    const response = await fetch(`${baseUrl}/canvas/operational?${params}`);

    if (!response.ok) {
      throw new Error(`Failed to fetch operational data: ${response.status}`);
    }

    const json = (await response.json()) as { data: OperationalCanvasData };
    dispatch.setOperationalData(json.data);
  } catch (error) {
    const message = error instanceof Error ? error.message : 'Unknown error';
    dispatch.setOperationalError(message);
  }
}

/**
 * Load detail canvas data from API
 *
 * Fetches full PM data with change history and constraint validation for the
 * DETAIL zoom level (16+). Shows 1-week detailed PM cards with editing.
 */
export async function loadDetailData(
  dispatch: {
    setDetailLoading: (loading: boolean) => void;
    setDetailData: (data: DetailCanvasData) => void;
    setDetailError: (error: string) => void;
  },
  options: { baseUrl?: string; fromDate?: string; toDate?: string; trainIds?: string[] } = {}
): Promise<void> {
  const {
    baseUrl = '/api/v1',
    fromDate,
    toDate,
    trainIds,
  } = options;

  dispatch.setDetailLoading(true);

  const params = new URLSearchParams();
  if (fromDate) {
    params.set('fromDate', fromDate);
  }
  if (toDate) {
    params.set('toDate', toDate);
  }
  if (trainIds && trainIds.length > 0) {
    params.set('trainIds', trainIds.join(','));
  }

  try {
    const response = await fetch(`${baseUrl}/canvas/detail?${params}`);

    if (!response.ok) {
      throw new Error(`Failed to fetch detail data: ${response.status}`);
    }

    const json = (await response.json()) as { data: DetailCanvasData };
    dispatch.setDetailData(json.data);
  } catch (error) {
    const message = error instanceof Error ? error.message : 'Unknown error';
    dispatch.setDetailError(message);
  }
}

