   525→          <TacticalGanttLayer
   526→            data={tacticalData}
   527→            trainOrder={trainIds}
   528→            fromDate={new Date(tacticalFromDate)}
   529→            toDate={new Date(tacticalToDate)}
   530→            width={containerWidth}
   531→            height={containerHeight}
   532→            selectedPmIds={canvasState.selection.selectedPmIds}
   533→            onPmClick={handlePmBlockClick}
   534→            onPmHover={handlePmBlockHover}
   535→            showConstraintWalls={layers.complianceWindows}
   536→            showGrid={true}
   537→          />
   538→          <div
   539→            ref={tooltipRef}
   540→            style={{
   541→              display: 'none',
   542→              position: 'fixed',
   543→              backgroundColor: 'white',
   544→              border: '1px solid #e2e8f0',
   545→              borderRadius: '6px',
   546→              padding: '8px 12px',
   547→              boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.1)',
   548→              pointerEvents: 'none',
   549→              zIndex: 100,
   550→              fontSize: '12px',
   551→              lineHeight: 1.5,
   552→            }}
   553→          />
   554→        </>
   555→      );
   556→    }
   557→
   558→    // OPERATIONAL and DETAIL zoom levels
   559→    if (zoomLevel === 'OPERATIONAL') {
   560→      if (operationalLoading) {
   561→        return (
   562→          <NonIdealState
   563→            icon={<Spinner size={48} />}
   564→            title="Loading operational view..."
   565→            description="Fetching detailed PM schedule data"
   566→          />
   567→        );
   568→      }
   569→
   570→      if (operationalError) {
   571→        return (
   572→          <NonIdealState
   573→            icon="error"
   574→            title="Error loading operational view"
   575→            description={operationalError}
   576→            action={
   577→              <Button intent="primary" onClick={handleLoadOperationalData}>
   578→                Retry
   579→              </Button>
   580→            }
   581→          />
   582→        );
   583→      }
   584→
   585→      if (!operationalData) {
   586→        return (
   587→          <NonIdealState
   588→            icon="id-number"
   589→            title="Operational View"
   590→            description="Load 4-week detailed PM cards with material status"
   591→            action={
   592→              <ButtonGroup>
   593→                <Button intent="primary" onClick={handleLoadOperationalData}>
   594→                  Load Operational Data
   595→                </Button>
   596→              </ButtonGroup>
   597→            }
   598→          >
   599→            <div style={{ marginTop: '16px', fontSize: '12px', color: 'var(--pt-text-muted)' }}>
   600→              <p>Shows PM schedule from {operationalFromDate} to {operationalToDate}</p>
   601→              <p>Daily granularity with detailed PM cards</p>
   602→            </div>
   603→          </NonIdealState>
   604→        );
   605→      }
   606→
   607→      const containerWidth = DEFAULT_CANVAS_WIDTH;
   608→      const containerHeight = DEFAULT_CANVAS_HEIGHT;
   609→
   610→      return (
   611→        <>
   612→          <OperationalDetailLayer
   613→            data={operationalData}
   614→            fromDate={new Date(operationalFromDate)}
   615→            toDate={new Date(operationalToDate)}
   616→            width={containerWidth}
   617→            height={containerHeight}
   618→            selectedPmIds={canvasState.selection.selectedPmIds}
   619→            onPmClick={handlePmBlockClick}
   620→            onPmHover={handleOperationalPmHover}
   621→            showGrid={true}
   622→          />
   623→          <div
   624→            ref={tooltipRef}
   625→            style={{
   626→              display: 'none',
   627→              position: 'fixed',
   628→              backgroundColor: 'white',
   629→              border: '1px solid #e2e8f0',
   630→              borderRadius: '6px',
   631→              padding: '12px 16px',
   632→              boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.1)',
   633→              pointerEvents: 'none',
   634→              zIndex: 100,
   635→              fontSize: '12px',
   636→              lineHeight: 1.6,
   637→              maxWidth: '350px',
   638→            }}
   639→          />
   640→        </>
   641→      );
   642→    }
   643→
   644→    // DETAIL view (zoom 16+) - React DOM overlay with full PM editing
   645→    if (detailLoading) {
   646→      return (
   647→        <NonIdealState
   648→          icon={<Spinner size={48} />}
   649→          title="Loading detail view..."
   650→          description="Fetching detailed PM data with history"
   651→        />
   652→      );
   653→    }
   654→
   655→    if (detailError) {
   656→      return (
   657→        <NonIdealState
   658→          icon="error"
   659→          title="Error loading detail view"
   660→          description={detailError}
   661→          action={
   662→            <Button intent="primary" onClick={handleLoadDetailData}>
   663→              Retry
   664→            </Button>
   665→          }
   666→        />
   667→      );
   668→    }
   669→
   670→    if (!detailData) {
   671→      return (
   672→        <NonIdealState
   673→          icon="document"
   674→          title="Detail View"
   675→          description="Load 1-week PM schedule with full editing capabilities"
   676→          action={
   677→            <ButtonGroup>
   678→              <Button intent="primary" onClick={handleLoadDetailData}>
   679→                Load Detail Data
   680→              </Button>
   681→            </ButtonGroup>
   682→          }
   683→        >
   684→          <div style={{ marginTop: '16px', fontSize: '12px', color: 'var(--pt-text-muted)' }}>
   685→            <p>Shows PM schedule from {detailFromDate} to {detailToDate}</p>
   686→            <ul style={{ textAlign: 'left', maxWidth: '300px', margin: '8px auto' }}>
   687→              <li>Full PM editing interface</li>
   688→              <li>Constraint validation feedback</li>
   689→              <li>Material availability status</li>
   690→              <li>Change history timeline</li>
   691→            </ul>
   692→          </div>
   693→        </NonIdealState>
   694→      );
   695→    }
   696→
   697→    return (
   698→      <DetailCardOverlay
   699→        data={detailData}
   700→        fromDate={new Date(detailFromDate)}
   701→        toDate={new Date(detailToDate)}
   702→        width={DEFAULT_CANVAS_WIDTH}
   703→        height={DEFAULT_CANVAS_HEIGHT}
   704→        selectedPmIds={canvasState.selection.selectedPmIds}
   705→        expandedPmIds={detailExpandedPmIds}
   706→        onPmSelect={handleDetailPmSelect}
   707→        onPmExpand={handleDetailPmExpand}
   708→        onPmCollapse={handleDetailPmCollapse}
   709→        onPmEdit={handleDetailPmEdit}
   710→        onPmLock={handleDetailPmLock}
   711→        onPmUnlock={handleDetailPmUnlock}
   712→        onViewHistory={handleDetailViewHistory}
   713→      />
   714→    );
   715→  };
   716→
   717→  return (
   718→    <div
   719→      className="mms-canvas"
   720→      style={{
   721→        flex: 1,
   722→        position: 'relative',
   723→        overflow: 'hidden',
   724→        backgroundColor: 'var(--pt-app-background-color, #f5f8fa)',
   725→        cursor: isPanning ? 'grabbing' : 'grab',
   726→      }}
   727→      onWheel={handleWheel}
   728→      onMouseDown={handleMouseDown}
   729→      onMouseUp={handleMouseUp}
   730→      onMouseLeave={handleMouseUp}
   731→      onMouseMove={handleMouseMove}
   732→    >
   733→      <div
   734→        style={{
   735→          position: 'absolute',
   736→          top: 0,
   737→          left: 0,
   738→          right: 0,
   739→          bottom: 0,
   740→          transform: `translate(${-canvasState.panX}px, ${-canvasState.panY}px)`,
   741→          transition: isPanning ? 'none' : 'transform 0.1s ease-out',
   742→        }}
   743→      >
   744→        {renderContent()}
   745→      </div>
   746→
   747→      <div style={{
   748→        position: 'absolute',
   749→        top: '12px',
   750→        right: '12px',
   751→        zIndex: 10,
   752→      }}>
   753→        <Card elevation={1} style={{ padding: '8px 12px' }}>
   754→          <div style={{ fontSize: '11px', color: 'var(--pt-text-muted)', marginBottom: '4px' }}>
   755→            Zoom Level
   756→          </div>
   757→          <div style={{ fontSize: '14px', fontWeight: 600 }}>
   758→            {zoomLevel.replace('_', ' ')}
   759→          </div>
   760→          <div style={{ fontSize: '11px', fontFamily: 'monospace' }}>
   761→            {zoom.toFixed(1)} / 20
   762→          </div>
   763→        </Card>
   764→      </div>
   765→
   766→      <div style={{
   767→        position: 'absolute',
   768→        bottom: '12px',
   769→        left: '12px',
   770→        zIndex: 10,
   771→      }}>
   772→        <Card elevation={1} style={{ padding: '8px 12px' }}>
