     1→/**
     2→ * Operational Detail Layer
     3→ *
     4→ * Konva-based detailed PM card layer for operational view (zoom levels 12-16).
     5→ * Renders individual PM cards with comprehensive information including:
     6→ * - Train identification with fleet colors
     7→ * - PM details (code, description, dates, status)
     8→ * - Track and depot assignment
     9→ * - Material availability indicators
    10→ * - Compliance window visualization
    11→ * - Action indicators (lock, edit, history)
    12→ *
    13→ * Features:
    14→ * - Card-based layout with vertical train stacking
    15→ * - Daily timeline granularity (4-week view)
    16→ * - Interactive hover and click handlers
    17→ * - Status-based color coding
    18→ * - Material availability badges
    19→ *
    20→ * @see specs/006-user-interface.md Section 6.3.4
    21→ */
    22→
    23→import { useRef } from 'react';
    24→import { Stage, Layer, Rect, Text, Line, Group } from 'react-konva';
    25→import type { Stage as StageType } from 'konva/lib/Stage';
    26→
    27→import type { OperationalPmBlock, OperationalCanvasData, MaterialStatus } from './types';
    28→import { PM_STATUS_COLORS, CONSTRAINT_COLORS, FLEET_COLORS, MATERIAL_STATUS_COLORS } from '../../theme/colors';
    29→
    30→// =============================================================================
    31→// Constants
    32→// =============================================================================
    33→
    34→/** Layout constants for operational cards */
    35→const LAYOUT = {
    36→  HEADER_HEIGHT: 64,
    37→  TRAIN_LABEL_WIDTH: 140,
    38→  CARD_WIDTH: 280,
    39→  CARD_HEIGHT: 180,
    40→  CARD_MARGIN: 12,
    41→  CARD_PADDING: 12,
    42→  DAY_WIDTH: 48,
    43→  ROW_HEIGHT: 200,
    44→  MIN_CARD_WIDTH: 200,
    45→  GRID_LINE_COLOR: '#e2e8f0',
    46→  HEADER_BG: '#f8fafc',
    47→  CARD_BG: '#ffffff',
    48→  FONT_FAMILY: '-apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif',
    49→};
    50→
    51→/** PM status to color mapping */
    52→function getPmStatusColor(status: string): string {
    53→  switch (status) {
    54→    case 'SCHEDULED':
    55→      return PM_STATUS_COLORS.scheduled;
    56→    case 'IN_PROGRESS':
    57→      return PM_STATUS_COLORS.inProgress;
    58→    case 'COMPLETED':
    59→      return PM_STATUS_COLORS.completed;
    60→    case 'CANCELLED':
    61→      return PM_STATUS_COLORS.cancelled;
    62→    case 'DEFERRED':
    63→      return PM_STATUS_COLORS.deferred;
    64→    default:
    65→      return PM_STATUS_COLORS.scheduled;
    66→  }
    67→}
    68→
    69→/** Material status to color mapping */
    70→function getMaterialStatusColor(status: MaterialStatus): string {
    71→  return MATERIAL_STATUS_COLORS[status] ?? MATERIAL_STATUS_COLORS.AVAILABLE;
    72→}
    73→
    74→/** Material status to icon mapping */
    75→function getMaterialStatusIcon(status: MaterialStatus): string {
    76→  switch (status) {
    77→    case 'AVAILABLE':
    78→      return '✓';
    79→    case 'LOW_STOCK':
    80→      return '⚠';
    81→    case 'UNAVAILABLE':
    82→      return '✗';
    83→    case 'ARRIVING':
    84→      return '⏳';
    85→    default:
    86→      return '?';
    87→  }
    88→}
    89→
    90→// =============================================================================
    91→// Types
    92→// =============================================================================
    93→
    94→export interface OperationalDetailLayerProps {
    95→  data: OperationalCanvasData | null;
    96→  fromDate: Date;
    97→  toDate: Date;
    98→  width: number;
    99→  height: number;
   100→  selectedPmIds?: string[];
   101→  onPmClick?: (pmId: string) => void;
   102→  onPmHover?: (pm: OperationalPmBlock | null) => void;
   103→  onPmEdit?: (pmId: string) => void;
   104→  onPmLock?: (pmId: string) => void;
   105→  showGrid?: boolean;
   106→}
   107→
   108→interface DayData {
   109→  date: Date;
   110→  dateStr: string;
   111→  dayOfWeek: number;
   112→  isWeekStart: boolean;
   113→  isToday: boolean;
   114→  label: string;
   115→}
   116→
   117→interface WeekData {
   118→  weekStart: Date;
   119→  weekNum: number;
   120→  month: string;
   121→  daysInWeek: number;
   122→}
   123→
   124→// =============================================================================
   125→// Pure Utility Functions
   126→// =============================================================================
   127→
   128→function getDays(fromDate: Date, toDate: Date): DayData[] {
   129→  const days: DayData[] = [];
   130→  const current = new Date(fromDate);
   131→  const today = new Date();
   132→  today.setHours(0, 0, 0, 0);
   133→
   134→  const dayNames = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
   135→
   136→  while (current <= toDate) {
   137→    const dayOfWeek = current.getDay();
   138→    days.push({
   139→      date: new Date(current),
   140→      dateStr: current.toISOString().split('T')[0],
   141→      dayOfWeek,
   142→      isWeekStart: dayOfWeek === 0,
   143→      isToday: current.getTime() === today.getTime(),
   144→      label: `${dayNames[dayOfWeek]} ${current.getDate()}`,
   145→    });
   146→    current.setDate(current.getDate() + 1);
   147→  }
   148→  return days;
   149→}
   150→
   151→function getWeeks(days: DayData[]): WeekData[] {
   152→  const weeks: WeekData[] = [];
   153→  let currentWeek: WeekData | null = null;
   154→  const monthNames = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'];
   155→
   156→  for (const day of days) {
   157→    if (day.isWeekStart || currentWeek === null) {
   158→      if (currentWeek) {
   159→        weeks.push(currentWeek);
   160→      }
   161→      const weekNum = getWeekNumber(day.date);
   162→      currentWeek = {
   163→        weekStart: day.date,
   164→        weekNum,
   165→        month: monthNames[day.date.getMonth()],
   166→        daysInWeek: 1,
   167→      };
   168→    } else {
   169→      currentWeek.daysInWeek++;
   170→    }
   171→  }
   172→  if (currentWeek) {
   173→    weeks.push(currentWeek);
   174→  }
   175→  return weeks;
   176→}
   177→
   178→function getWeekNumber(date: Date): number {
   179→  const d = new Date(Date.UTC(date.getFullYear(), date.getMonth(), date.getDate()));
   180→  const dayNum = d.getUTCDay() || 7;
   181→  d.setUTCDate(d.getUTCDate() + 4 - dayNum);
   182→  const yearStart = new Date(Date.UTC(d.getUTCFullYear(), 0, 1));
   183→  return Math.ceil(((d.getTime() - yearStart.getTime()) / 86400000 + 1) / 7);
   184→}
   185→
   186→function dateDiffDays(a: Date, b: Date): number {
   187→  return Math.floor((a.getTime() - b.getTime()) / (1000 * 60 * 60 * 24));
   188→}
   189→
   190→function parseDate(dateStr: string): Date {
   191→  return new Date(dateStr + 'T00:00:00');
   192→}
   193→
   194→function formatDateRange(startDate: string, endDate: string): string {
   195→  const start = new Date(startDate);
   196→  const end = new Date(endDate);
   197→  const monthNames = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'];
   198→
   199→  if (startDate === endDate) {
   200→    return `${monthNames[start.getMonth()]} ${start.getDate()}`;
   201→  }
   202→
   203→  if (start.getMonth() === end.getMonth()) {
   204→    return `${monthNames[start.getMonth()]} ${start.getDate()}-${end.getDate()}`;
   205→  }
   206→
   207→  return `${monthNames[start.getMonth()]} ${start.getDate()} - ${monthNames[end.getMonth()]} ${end.getDate()}`;
   208→}
   209→
   210→function buildTrainGroups(pmBlocks: OperationalPmBlock[]): Map<string, OperationalPmBlock[]> {
   211→  const groups = new Map<string, OperationalPmBlock[]>();
   212→
   213→  for (const pm of pmBlocks) {
   214→    if (!groups.has(pm.trainId)) {
   215→      groups.set(pm.trainId, []);
   216→    }
   217→    groups.get(pm.trainId)!.push(pm);
   218→  }
   219→
   220→  return groups;
   221→}
