   208→function getDays(fromDate: Date, toDate: Date): Date[] {
   209→  const days: Date[] = [];
   210→  const current = new Date(fromDate);
   211→  while (current <= toDate) {
   212→    days.push(new Date(current));
   213→    current.setDate(current.getDate() + 1);
   214→  }
   215→  return days;
