   254→  if (progress > 90 || daysRemaining < 0) {
   255→    status = 'violation';
   256→  } else if (progress > 70 || daysRemaining < 7) {
   257→    status = 'approaching';
   258→  }
   259→
   260→  return { progress, daysRemaining, status };
