   567→        minHeight: isExpanded ? LAYOUT.CARD_EXPANDED_HEIGHT : LAYOUT.CARD_HEIGHT,
   568→        borderLeft: `4px solid ${statusColor}`,
   569→        outline: isSelected ? `2px solid #3b82f6` : 'none',
   570→        outlineOffset: 2,
   571→        transition: 'all 0.2s ease',
   572→        position: 'relative',
   573→        overflow: 'hidden',
   574→      }}
   575→    >
   576→      {/* Header */}
   577→      <div style={{ display: 'flex', alignItems: 'flex-start', marginBottom: 12 }}>
   578→        <div style={{ flex: 1 }}>
   579→          <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
   580→            <span style={{ fontSize: 16, fontWeight: 600, color: '#1e293b' }}>
   581→              {pm.pmCode}
   582→            </span>
   583→            <Tag minimal intent={getPmStatusIntent(pm.status)}>
   584→              {pm.status.replace('_', ' ')}
   585→            </Tag>
   586→            {pm.isLocked && (
   587→              <Tooltip content="Locked in Maximo - Cannot be modified" position={Position.TOP}>
   588→                <Icon icon="lock" size={14} style={{ color: '#d97706' }} />
   589→              </Tooltip>
   590→            )}
   591→          </div>
   592→          <div style={{ fontSize: 12, color: '#64748b', marginTop: 4 }}>
   593→            {pm.pmDescription}
   594→          </div>
   595→        </div>
   596→        <div style={{ display: 'flex', alignItems: 'center', gap: 4 }}>
   597→          {isExpanded ? (
   598→            <Button small minimal icon="collapse-all" onClick={onCollapse} />
   599→          ) : (
   600→            <Button small minimal icon="expand-all" onClick={onExpand} />
   601→          )}
   602→          <Popover content={actionMenu} position={Position.BOTTOM_RIGHT}>
   603→            <Button small minimal icon="more" />
   604→          </Popover>
   605→        </div>
   606→      </div>
   607→
   608→      {/* Train info row */}
   609→      <div style={{ display: 'flex', alignItems: 'center', gap: 12, marginBottom: 12 }}>
   610→        <div
   611→          style={{
   612→            display: 'flex',
   613→            alignItems: 'center',
   614→            gap: 6,
   615→            padding: '4px 8px',
   616→            backgroundColor: `${fleetColor}15`,
   617→            borderRadius: 4,
   618→          }}
   619→        >
   620→          <div
   621→            style={{
   622→              width: 4,
   623→              height: 16,
   624→              backgroundColor: fleetColor,
   625→              borderRadius: 2,
   626→            }}
   627→          />
   628→          <span style={{ fontSize: 13, fontWeight: 500, color: '#1e293b' }}>
   629→            {pm.trainNumber}
   630→          </span>
   631→          <span style={{ fontSize: 11, color: '#64748b' }}>{pm.fleetCode}</span>
   632→        </div>
   633→        {pm.depotCode && (
   634→          <div style={{ fontSize: 12, color: '#64748b' }}>
   635→            <Icon icon="office" size={12} style={{ marginRight: 4 }} />
   636→            {pm.depotCode}
   637→          </div>
   638→        )}
   639→        {pm.trackNumber && (
   640→          <div style={{ fontSize: 12, color: '#64748b' }}>
   641→            <Icon icon="layout-grid" size={12} style={{ marginRight: 4 }} />
   642→            Track {pm.trackNumber}
   643→          </div>
   644→        )}
   645→      </div>
   646→
   647→      {/* Date and duration row */}
   648→      <div style={{ display: 'flex', gap: 16, marginBottom: 12 }}>
   649→        <div>
   650→          <div style={{ fontSize: 10, color: '#94a3b8', textTransform: 'uppercase' }}>Date</div>
   651→          <div style={{ fontSize: 13, fontWeight: 500, color: '#1e293b' }}>
   652→            {formatDate(pm.targetDate)}
   653→            {pm.durationDays > 1 && (
   654→              <span style={{ color: '#64748b', fontWeight: 400 }}>
   655→                {' '}
   656→                - {formatDate(pm.endDate)}
   657→              </span>
   658→            )}
   659→          </div>
   660→        </div>
   661→        <div>
   662→          <div style={{ fontSize: 10, color: '#94a3b8', textTransform: 'uppercase' }}>Duration</div>
   663→          <div style={{ fontSize: 13, fontWeight: 500, color: '#1e293b' }}>
   664→            {pm.durationDays} day{pm.durationDays > 1 ? 's' : ''}
   665→            {pm.estimatedHours && (
   666→              <span style={{ color: '#64748b', fontWeight: 400 }}> ({pm.estimatedHours}h)</span>
   667→            )}
   668→          </div>
   669→        </div>
   670→        {pm.assignedShift && (
   671→          <div>
   672→            <div style={{ fontSize: 10, color: '#94a3b8', textTransform: 'uppercase' }}>Shift</div>
   673→            <div style={{ fontSize: 13, fontWeight: 500, color: '#1e293b' }}>{pm.assignedShift}</div>
   674→          </div>
   675→        )}
   676→      </div>
   677→
   678→      {/* Compliance timeline */}
   679→      <ComplianceTimeline pm={pm} />
   680→
   681→      {/* Expanded content */}
   682→      <Collapse isOpen={isExpanded}>
   683→        <Divider style={{ margin: '16px 0' }} />
   684→
   685→        {/* Materials section */}
   686→        <div ref={materialsRef}>
   687→          <div style={{ fontSize: 12, fontWeight: 600, color: '#475569', marginBottom: 8 }}>
   688→            <Icon icon="box" size={12} style={{ marginRight: 6 }} />
   689→            Materials
   690→          </div>
   691→          <MaterialsSection materials={pm.materials} />
   692→        </div>
   693→
   694→        <Divider style={{ margin: '16px 0' }} />
   695→
   696→        {/* Constraint validation */}
   697→        <div ref={constraintsRef}>
   698→          <div style={{ fontSize: 12, fontWeight: 600, color: '#475569', marginBottom: 8 }}>
   699→            <Icon icon="shield" size={12} style={{ marginRight: 6 }} />
   700→            Constraint Validation
   701→          </div>
   702→          <ConstraintValidationSection validation={pm.constraintValidation} />
   703→        </div>
   704→
   705→        <Divider style={{ margin: '16px 0' }} />
   706→
   707→        {/* Change history */}
   708→        <div ref={historyRef}>
   709→          <div style={{ fontSize: 12, fontWeight: 600, color: '#475569', marginBottom: 8 }}>
   710→            <Icon icon="history" size={12} style={{ marginRight: 6 }} />
   711→            Recent Changes
   712→          </div>
   713→          <ChangeHistorySection history={pm.changeHistory} />
   714→        </div>
   715→
   716→        {/* Actions footer */}
   717→        <Divider style={{ margin: '16px 0' }} />
   718→        <ButtonGroup fill>
   719→          <Button
   720→            icon="edit"
   721→            text="Edit"
   722→            disabled={pm.isLocked}
   723→            onClick={() => onEdit?.('all', null)}
   724→          />
   725→          <Button
   726→            icon="calendar"
   727→            text="Reschedule"
   728→            disabled={pm.isLocked}
   729→            onClick={() => onEdit?.('targetDate', null)}
   730→          />
   731→          {pm.isLocked ? (
   732→            <Button icon="unlock" text="Unlock" intent={Intent.WARNING} onClick={onUnlock} />
   733→          ) : (
   734→            <Button icon="lock" text="Lock" onClick={onLock} />
   735→          )}
   736→          <Button icon="history" text="History" onClick={onViewHistory} />
   737→        </ButtonGroup>
   738→      </Collapse>
   739→    </Card>
   740→  );
   741→}
   742→
   743→// =============================================================================
   744→// Main Component
   745→// =============================================================================
   746→
   747→export function DetailCardOverlay({
   748→  data,
   749→  fromDate,
   750→  toDate,
   751→  width,
   752→  height,
   753→  selectedPmIds = [],
   754→  expandedPmIds = [],
   755→  onPmSelect,
   756→  onPmExpand,
   757→  onPmCollapse,
   758→  onPmEdit,
   759→  onPmLock,
   760→  onPmUnlock,
   761→  onViewHistory,
   762→}: DetailCardOverlayProps) {
   763→  const containerRef = useRef<HTMLDivElement>(null);
   764→
   765→  if (!data) {
   766→    return null;
   767→  }
   768→
   769→  const days = getDays(fromDate, toDate);
   770→  const trainGroups = buildTrainGroups(data.pmBlocks);
   771→  const trainOrder = Array.from(trainGroups.keys());
   772→  const selectedSet = new Set(selectedPmIds);
   773→  const expandedSet = new Set(expandedPmIds);
   774→
   775→  const today = new Date();
   776→  today.setHours(0, 0, 0, 0);
   777→
   778→  return (
   779→    <div
   780→      ref={containerRef}
   781→      style={{
   782→        width,
   783→        height,
   784→        overflow: 'auto',
   785→        backgroundColor: '#f8fafc',
   786→        fontFamily: LAYOUT.FONT_FAMILY,
   787→      }}
   788→    >
   789→      {/* Timeline header */}
   790→      <div
   791→        style={{
   792→          position: 'sticky',
   793→          top: 0,
   794→          zIndex: 10,
   795→          display: 'flex',
   796→          backgroundColor: '#ffffff',
   797→          borderBottom: '1px solid #e2e8f0',
   798→        }}
   799→      >
   800→        {/* Train label header */}
   801→        <div
   802→          style={{
   803→            width: LAYOUT.TRAIN_LABEL_WIDTH,
   804→            minWidth: LAYOUT.TRAIN_LABEL_WIDTH,
   805→            height: LAYOUT.HEADER_HEIGHT,
   806→            padding: 16,
   807→            backgroundColor: '#f8fafc',
   808→            borderRight: '1px solid #e2e8f0',
   809→            display: 'flex',
   810→            flexDirection: 'column',
   811→            justifyContent: 'center',
   812→          }}
   813→        >
   814→          <div style={{ fontSize: 14, fontWeight: 600, color: '#1e293b' }}>Trains</div>
   815→          <div style={{ fontSize: 11, color: '#64748b' }}>{trainOrder.length} trains</div>
   816→        </div>
   817→
   818→        {/* Day columns */}
   819→        <div style={{ display: 'flex' }}>
   820→          {days.map((day) => {
   821→            const isToday = day.getTime() === today.getTime();
   822→            const isWeekend = day.getDay() === 0 || day.getDay() === 6;
   823→            const dayNames = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
   824→
   825→            return (
   826→              <div
   827→                key={day.toISOString()}
   828→                style={{
   829→                  width: LAYOUT.DAY_WIDTH,
   830→                  minWidth: LAYOUT.DAY_WIDTH,
   831→                  height: LAYOUT.HEADER_HEIGHT,
   832→                  padding: '12px 8px',
   833→                  backgroundColor: isToday ? '#dbeafe' : isWeekend ? '#f1f5f9' : '#ffffff',
   834→                  borderRight: '1px solid #e2e8f0',
   835→                  textAlign: 'center',
   836→                }}
   837→              >
   838→                <div
   839→                  style={{
   840→                    fontSize: 10,
   841→                    color: isToday ? '#2563eb' : '#94a3b8',
   842→                    textTransform: 'uppercase',
   843→                    letterSpacing: '0.5px',
   844→                  }}
   845→                >
   846→                  {dayNames[day.getDay()]}
   847→                </div>
   848→                <div
   849→                  style={{
   850→                    fontSize: 20,
   851→                    fontWeight: isToday ? 700 : 500,
   852→                    color: isToday ? '#2563eb' : '#1e293b',
   853→                    marginTop: 4,
   854→                  }}
   855→                >
   856→                  {day.getDate()}
   857→                </div>
   858→                <div style={{ fontSize: 11, color: '#64748b' }}>
   859→                  {day.toLocaleDateString('en-US', { month: 'short' })}
   860→                </div>
   861→              </div>
   862→            );
   863→          })}
   864→        </div>
   865→      </div>
   866→
   867→      {/* Train rows */}
   868→      {trainOrder.map((trainId) => {
   869→        const pms = trainGroups.get(trainId) || [];
   870→        const firstPm = pms[0];
   871→        if (!firstPm) return null;
   872→
   873→        const fleetColor = FLEET_COLORS[firstPm.fleetCode as keyof typeof FLEET_COLORS] || FLEET_COLORS.KS;
   874→        const hasExpandedCard = pms.some((pm) => expandedSet.has(pm.pmId));
   875→        const rowHeight = hasExpandedCard ? LAYOUT.EXPANDED_ROW_HEIGHT : LAYOUT.ROW_HEIGHT;
   876→
   877→        return (
   878→          <div
   879→            key={trainId}
   880→            style={{
   881→              display: 'flex',
   882→              borderBottom: '1px solid #e2e8f0',
   883→              minHeight: rowHeight,
   884→            }}
   885→          >
   886→            {/* Train label */}
   887→            <div
   888→              style={{
   889→                width: LAYOUT.TRAIN_LABEL_WIDTH,
   890→                minWidth: LAYOUT.TRAIN_LABEL_WIDTH,
   891→                padding: 16,
   892→                backgroundColor: '#ffffff',
   893→                borderRight: '1px solid #e2e8f0',
   894→                position: 'sticky',
   895→                left: 0,
   896→                zIndex: 5,
   897→              }}
   898→            >
   899→              <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
   900→                <div
   901→                  style={{
   902→                    width: 4,
   903→                    height: 32,
   904→                    backgroundColor: fleetColor,
   905→                    borderRadius: 2,
   906→                  }}
   907→                />
   908→                <div>
   909→                  <div style={{ fontSize: 14, fontWeight: 600, color: '#1e293b' }}>
   910→                    {firstPm.trainNumber}
   911→                  </div>
   912→                  <div style={{ fontSize: 11, color: '#64748b' }}>{firstPm.fleetCode}</div>
   913→                </div>
   914→              </div>
   915→              <div style={{ marginTop: 12, fontSize: 11, color: '#94a3b8' }}>
   916→                {pms.length} PM{pms.length !== 1 ? 's' : ''} scheduled
   917→              </div>
   918→            </div>
   919→
   920→            {/* PM cards grid */}
   921→            <div style={{ flex: 1, position: 'relative', padding: LAYOUT.CARD_MARGIN }}>
   922→              {pms.map((pm) => {
   923→                const pmDate = parseDate(pm.targetDate);
   924→                const dayOffset = dateDiffDays(pmDate, fromDate);
   925→                if (dayOffset < 0) return null;
   926→
   927→                const isSelected = selectedSet.has(pm.pmId);
   928→                const isExpanded = expandedSet.has(pm.pmId);
   929→
   930→                const cardX = dayOffset * LAYOUT.DAY_WIDTH;
   931→
   932→                return (
   933→                  <div
   934→                    key={pm.pmId}
   935→                    style={{
   936→                      position: 'absolute',
   937→                      left: cardX,
   938→                      top: 0,
   939→                      zIndex: isExpanded ? 20 : isSelected ? 15 : 10,
   940→                    }}
   941→                  >
   942→                    <DetailCard
   943→                      pm={pm}
   944→                      isSelected={isSelected}
   945→                      isExpanded={isExpanded}
   946→                      onSelect={() => onPmSelect?.(pm.pmId)}
   947→                      onExpand={() => onPmExpand?.(pm.pmId)}
   948→                      onCollapse={() => onPmCollapse?.(pm.pmId)}
   949→                      onEdit={(field, value) => onPmEdit?.(pm.pmId, field, value)}
   950→                      onLock={() => onPmLock?.(pm.pmId)}
   951→                      onUnlock={() => onPmUnlock?.(pm.pmId)}
   952→                      onViewHistory={() => onViewHistory?.(pm.pmId)}
   953→                    />
   954→                  </div>
   955→                );
   956→              })}
   957→
   958→              {/* Today indicator line */}
   959→              {(() => {
   960→                const todayOffset = dateDiffDays(today, fromDate);
   961→                if (todayOffset >= 0 && todayOffset < days.length) {
   962→                  return (
   963→                    <div
   964→                      style={{
   965→                        position: 'absolute',
   966→                        left: todayOffset * LAYOUT.DAY_WIDTH + LAYOUT.DAY_WIDTH / 2,
   967→                        top: 0,
   968→                        bottom: 0,
   969→                        width: 2,
   970→                        backgroundColor: '#2563eb',
   971→                        opacity: 0.3,
   972→                        zIndex: 1,
   973→                      }}
   974→                    />
   975→                  );
   976→                }
   977→                return null;
   978→              })()}
   979→            </div>
   980→          </div>
   981→        );
   982→      })}
   983→    </div>
   984→  );
   985→}
   986→
   987→export default DetailCardOverlay;
